UPDATE auth_rule_param
name = #{name}, name_en = #{nameEn}, business_objects = #{businessObjects}, value_logics = #{valueLogics}, is_active = #{isActive}, data_type = #{dataType}, updated_by = #{updatedBy}, updated_time = #{updatedTime}
